// HasRecordTask applies the HasEdge predicate on the "record_task" edge.
func HasRecordTask() predicate.UploadTask {
	return predicate.UploadTask(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2O, true, RecordTaskTable, RecordTaskColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRecordTaskWith applies the HasEdge predicate on the "record_task" edge with a given conditions (other predicates).
func HasRecordTaskWith(preds ...predicate.RecordTask) predicate.UploadTask {
	return predicate.UploadTask(func(s *sql.Selector) {
		step := newRecordTaskStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

